    # like '100k-1m', '<3', '>5', '7.7%-8.3%'
    s = s.strip()
    def num(x):
        x=x.strip().replace('%','')
        mul=1
        if x.endswith('k'): mul=1000; x=x[:-1]
        elif x.endswith('m'): mul=1000000; x=x[:-1]
        return float(x)*mul
    if '-' in s and not s.startswith('-'):
        a,b=s.split('-')
        return num(a)<=val<=num(b)
    if s.startswith('<'):
        return val<num(s[1:])
    if s.startswith('>'):
        return val>num(s[1:])
    return True

